parameters.jsCode:
const input = $input.first().json;
const output = input.output || input;
const queries = output.queries || [];

return queries.map(query => ({
  json: {
    user_question: output.user_question || "",
    analysis_goal: output.analysis_goal,
    final_instruction: output.final_instruction,
    query_id: query.id,
    purpose: query.purpose,
    sql: query.sql
  }
}));

const input = $input.first().json;

const sql =
  input.sql ||
  input.output?.queries?.[0]?.sql ||
  input.queries?.[0]?.sql ||
  "";

if (!sql) {
  throw new Error("SQL is empty. Check input structure.");
}

const forbidden = /\b(INSERT|UPDATE|DELETE|DROP|ALTER|TRUNCATE|CREATE|GRANT|REVOKE|MERGE|CALL|EXECUTE)\b/i;

if (forbidden.test(sql)) {
  throw new Error(`Blocked unsafe SQL:\n${sql}`);
}

const allowedStart = /^\s*(SELECT|WITH)\b/i;

if (!allowedStart.test(sql)) {
  throw new Error(`Only SELECT or WITH queries are allowed:\n${sql}`);
}

const suspicious = /\b(pg_|information_schema|auth\.|storage\.|extensions)\b/i;

if (suspicious.test(sql)) {
  throw new Error(`Blocked system schema access:\n${sql}`);
}

return [
  {
    json: input
  }
];

const rows = $input.all().map(item => item.json);

const loop = $("Loop Over Items").item.json;

const result = {
  user_question: loop.user_question,
  analysis_goal: loop.analysis_goal,
  final_instruction: loop.final_instruction,
  query_id: loop.query_id,
  purpose: loop.purpose,
  sql: loop.sql,
  row_count: rows.length,
  rows
};

const staticData = $getWorkflowStaticData('global');

if (!staticData.query_results) {
  staticData.query_results = [];
}

staticData.query_results.push(result);

return [
  {
    json: result
  }
];

const staticData = $getWorkflowStaticData('global');

const results = staticData.query_results || [];

if (!results.length) {
  throw new Error("No query results found.");
}

return [
  {
    json: {
      user_question: results[0].user_question,
      analysis_goal: results[0].analysis_goal,
      final_instruction: results[0].final_instruction,
      query_count: results.length,
      query_results: results
    }
  }
];
